[Sun 2026-04-05 15:59 UTC] [Subagent Context] You are running as a subagent (depth 1/1). Results auto-announce to your requester; do not busy-poll for status.

[Subagent Task]: # D&D Remodel — Agent 1: Backend (AI Chat Endpoint)

Add AI Assistant endpoint to ~/dnd-app/backend/server.js. Do NOT touch frontend files.

## Read First
- ~/dnd-app/backend/server.js (full file — understand existing patterns, especially POST /api/rooms/:pin/summary which already uses Bedrock)
- ~/dnd-app/backend/bestiary-data.js
- ~/dnd-app/backend/spells-data.js

## Deliverable: POST /api/rooms/:pin/ai-chat

### Context Gathering
Before calling Bedrock, gather session context:
```javascript
function gatherSessionContext(room) {
  const ctx = []

  // Party info
  if (room.players?.length) {
    ctx.push('## Current Party')
    for (const p of room.players) {
      const char = p.character || {}
      ctx.push(`- **${p.name}** (${char.race || '?'} ${char.class || '?'} Lv${char.level || 1}) HP: ${char.hp || '?'}/${char.maxHp || '?'} AC: ${char.ac || '?'}`)
    }
  }

  // Initiative order (if combat active)
  if (room.initiative?.length) {
    ctx.push('\n## Initiative Order')
    room.initiative.forEach((entry, i) => {
      ctx.push(`${i + 1}. ${entry.name} (${entry.initiative})${entry.current ? ' ← CURRENT TURN' : ''}`)
    })
  }

  // Recent dice rolls (last 10)
  if (room.rolls?.length) {
    ctx.push('\n## Recent Dice Rolls')
    room.rolls.slice(-10).forEach(r => {
      ctx.push(`- ${r.player}: ${r.notation} = **${r.total}** ${r.details || ''}`)
    })
  }

  // Session notes
  if (room.notes) {
    ctx.push('\n## Session Notes')
    ctx.push(room.notes)
  }

  return ctx.join('\n')
}
```

### System Prompt
```
You are a D&D 5e (2024 rules) game assistant. You help both DMs and Players.

Your knowledge:
- All D&D 2024 Player's Handbook rules
- Monsters, spells, items, conditions
- Creative encounter design
- NPC roleplay and voices
- Rules interpretation

Current session context:
{sessionContext}

Guidelines:
- Be concise but helpful
- Use D&D terminology correctly
- When suggesting encounters, consider party level and composition
- When asked about rules, cite the relevant rule
- For roleplay, be creative and engaging
- If asked to make a decision for a player, suggest options instead
- Respond in the same language the user writes in
- Use emoji for flavor (⚔️ for combat, 🎲 for dice, 🧙 for magic, etc.)
```

### Endpoint Implementation
```javascript
// AI Chat for D&D sessions
const AI_CHAT_HISTORY = {} // roomPin → [{role, content}]

app.post('/api/rooms/:pin/ai-chat', async (req, res) => {
  const { message } = req.body
  if (!message) return res.status(400).json({ ok: false, error: 'Message required' })

  const room = findRoomByAnyPin(req.params.pin)
  if (!room) return res.status(404).json({ ok: false, error: 'Room not found' })

  const roomPin = room.dmPin || req.params.pin

  // Initialize history
  if (!AI_CHAT_HISTORY[roomPin]) AI_CHAT_HISTORY[roomPin] = []
  const history = AI_CHAT_HISTORY[roomPin]

  // Gather context
  const context = gatherSessionContext(room)

  // Add user message
  history.push({ role: 'user', content: message })

  // Keep last 20 messages
  if (history.length > 20) history.splice(0, history.length - 20)

  // Build messages for Bedrock
  const systemPrompt = `You are a D&D 5e (2024 rules) game assistant...` // full prompt above

  // Call Bedrock (same pattern as /api/rooms/:pin/summary)
  try {
    const response = await callBedrock(systemPrompt + '\n\n' + context, history)
    history.push({ role: 'assistant', content: response })
    res.json({ ok: true, response, historyLength: history.length })
  } catch (e) {
    res.status(500).json({ ok: false, error: e.message })
  }
})

// Clear AI chat history
app.delete('/api/rooms/:pin/ai-chat', (req, res) => {
  const room = findRoomByAnyPin(req.params.pin)
  if (!room) return res.status(404).json({ ok: false, error: 'Room not found' })
  const roomPin = room.dmPin || req.params.pin
  AI_CHAT_HISTORY[roomPin] = []
  res.json({ ok: true })
})
```

### Important: Reuse Existing Bedrock Code
The existing `POST /api/rooms/:pin/summary` already calls Bedrock. Find that function and reuse the same Bedrock client/invocation pattern. Do NOT create a new Bedrock client — reuse the existing one.

Look for the BedrockRuntimeClient setup and the InvokeModelWithResponseStream pattern.

### Rate Limiting
Add simple rate limit: max 1 AI request per 3 seconds per room.
```javascript
const AI_RATE_LIMIT = {}
// Before calling Bedrock:
const now = Date.now()
if (AI_RATE_LIMIT[roomPin] && now - AI_RATE_LIMIT[roomPin] < 3000) {
  return res.status(429).json({ ok: false, error: 'Please wait a moment before asking again' })
}
AI_RATE_LIMIT[roomPin] = now
```

### Also: findRoomByAnyPin helper
Check if this already exists. If not, create one that searches rooms by dmPin OR player pin:
```javascript
function findRoomByAnyPin(pin) {
  // Check DM pins
  if (rooms[pin]) return rooms[pin]
  // Check player pins
  for (const room of Object.values(rooms)) {
    if (room.players?.some(p => p.pin === pin)) return room
  }
  return null
}
```

## Rules
- Read server.js FULLY first
- Reuse existing Bedrock client (do not create new AWS client)
- Follow existing code patterns (error handling, response format)
- Do NOT modify frontend files
- Test that PM2 restart works after changes
- Keep all existing endpoints working

const express = require('express');
const http = require('http');
const WebSocket = require('ws');
const { v4: uuidv4 } = require('uuid');
const fs = require('fs');
const path = require('path');
const cors = require('cors');

const app = express();
const server = http.createServer(app);
const wss = new WebSocket.Server({ server });

const PORT = 3004;
const DATA_DIR = path.join(__dirname, '..', 'data');

// Ensure data directory
if (!fs.existsSync(DATA_DIR)) fs.mkdirSync(DATA_DIR, { recursive: true });

app.use(cors());
app.use(express.json({ limit: '50mb' }));

// --- Data helpers ---
function readJSON(file) {
  const fp = path.join(DATA_DIR, file);
  if (!fs.existsSync(fp)) return {};
  try { return JSON.parse(fs.readFileSync(fp, 'utf8')); } catch { return {}; }
}

function writeJSON(file, data) {
  fs.writeFileSync(path.join(DATA_DIR, file), JSON.stringify(data, null, 2));
  // Auto-backup for rooms.json and characters.json
  if (file === 'rooms.json' || file === 'characters.json') {
    createBackup(file, data);
  }
}

// --- Backup system ---
const BACKUP_DIR = path.join(DATA_DIR, 'backups');
if (!fs.existsSync(BACKUP_DIR)) fs.mkdirSync(BACKUP_DIR, { recursive: true });

function createBackup(file, data) {
  try {
    const today = new Date().toISOString().slice(0, 10); // YYYY-MM-DD
    const baseName = file.replace('.json', '');
    const backupFile = path.join(BACKUP_DIR, `${baseName}-${today}.json`);
    fs.writeFileSync(backupFile, JSON.stringify(data, null, 2));
    cleanOldBackups(baseName);
  } catch (e) {
    console.error('Backup failed for', file, e.message);
  }
}

function cleanOldBackups(baseName) {
  try {
    const files = fs.readdirSync(BACKUP_DIR)
      .filter(f => f.startsWith(baseName + '-') && f.endsWith('.json'))
      .sort()
      .reverse();
    // Keep last 7 days
    const toDelete = files.slice(7);
    toDelete.forEach(f => {
      fs.unlinkSync(path.join(BACKUP_DIR, f));
    });
  } catch (e) {
    console.error('Backup cleanup failed:', e.message);
  }
}

function readArray(file) {
  const fp = path.join(DATA_DIR, file);
  if (!fs.existsSync(fp)) return [];
  try { return JSON.parse(fs.readFileSync(fp, 'utf8')); } catch { return []; }
}

function writeArray(file, data) {
  fs.writeFileSync(path.join(DATA_DIR, file), JSON.stringify(data, null, 2));
}

// --- PIN Generation Helpers ---
function generate6DigitPin(rooms) {
  let pin;
  do {
    pin = String(Math.floor(100000 + Math.random() * 900000));
  } while (rooms[pin]);
  return pin;
}

function generate4DigitPin(rooms) {
  // Must be unique across ALL rooms and ALL players
  const usedPins = new Set();
  for (const roomPin of Object.keys(rooms)) {
    const room = rooms[roomPin];
    if (room.players) {
      for (const p of room.players) {
        if (p.pin) usedPins.add(p.pin);
      }
    }
  }
  let pin;
  let attempts = 0;
  do {
    pin = String(Math.floor(1000 + Math.random() * 9000));
    attempts++;
    if (attempts > 5000) throw new Error('Could not generate unique 4-digit PIN');
  } while (usedPins.has(pin));
  return pin;
}

// --- WebSocket connections by room ---
const roomConnections = {}; // { roomPin: Set<ws> }
const wsUserMap = new WeakMap(); // ws -> { roomPin, userId, userName, isDM }

wss.on('connection', (ws) => {
  ws.isAlive = true;
  ws.on('pong', () => { ws.isAlive = true; });

  ws.on('message', (raw) => {
    let msg;
    try { msg = JSON.parse(raw); } catch { return; }

    switch (msg.type) {
      case 'join-room': {
        const { roomPin, userId, userName, isDM, isSpectator } = msg;
        wsUserMap.set(ws, { roomPin, userId, userName, isDM, isSpectator: isSpectator || false });
        if (!roomConnections[roomPin]) roomConnections[roomPin] = new Set();
        roomConnections[roomPin].add(ws);
        // Notify room
        broadcastToRoom(roomPin, { type: 'user-joined', userId, userName, isDM, isSpectator: isSpectator || false });
        // Send spectator count
        broadcastSpectatorCount(roomPin);
        // Send system chat message for join
        if (!isSpectator) {
          const joinMsg = { sender: 'System', text: `${userName} joined the room`, timestamp: Date.now(), isSystem: true };
          saveChatMessage(roomPin, joinMsg);
          broadcastToRoom(roomPin, { type: 'chat_message', data: joinMsg });
        }
        break;
      }
      case 'dice-roll': {
        const info = wsUserMap.get(ws);
        if (info) {
          const rollData = { ...msg, userId: info.userId, userName: info.userName, timestamp: Date.now() };
          // Save to roll history
          saveRollHistory(info.roomPin, rollData);
          broadcastToRoom(info.roomPin, { type: 'dice-roll', data: rollData });
        }
        break;
      }
      case 'initiative-update': {
        const info = wsUserMap.get(ws);
        if (info) {
          broadcastToRoom(info.roomPin, { type: 'initiative-update', data: msg.data });
        }
        break;
      }
      case 'character_update': {
        const info2 = wsUserMap.get(ws);
        if (info2) {
          broadcastToRoom(info2.roomPin, { type: 'character_update', data: msg.data, userId: info2.userId });
        }
        break;
      }
      case 'chat-message': {
        const info = wsUserMap.get(ws);
        if (info) {
          broadcastToRoom(info.roomPin, { type: 'chat-message', userId: info.userId, userName: info.userName, message: msg.message, timestamp: Date.now() });
        }
        break;
      }
      case 'player-added': {
        const info = wsUserMap.get(ws);
        if (info) {
          broadcastToRoom(info.roomPin, { type: 'player-added', data: msg.data });
        }
        break;
      }
      case 'player-removed': {
        const info = wsUserMap.get(ws);
        if (info) {
          broadcastToRoom(info.roomPin, { type: 'player-removed', data: msg.data });
        }
        break;
      }
      case 'map_update': {
        const info = wsUserMap.get(ws);
        if (info) {
          // Persist map state
          const rooms = readJSON('rooms.json');
          if (rooms[info.roomPin]) {
            rooms[info.roomPin].mapState = msg.data;
            writeJSON('rooms.json', rooms);
          }
          broadcastToRoom(info.roomPin, { type: 'map_update', data: msg.data, userId: info.userId });
        }
        break;
      }
      case 'token_move': {
        const info = wsUserMap.get(ws);
        if (info) {
          // Persist token position
          const rooms = readJSON('rooms.json');
          if (rooms[info.roomPin]) {
            if (!rooms[info.roomPin].tokens) rooms[info.roomPin].tokens = {};
            if (msg.data && msg.data.id) {
              rooms[info.roomPin].tokens[msg.data.id] = { x: msg.data.x, y: msg.data.y, ...msg.data };
            }
            writeJSON('rooms.json', rooms);
          }
          broadcastToRoom(info.roomPin, { type: 'token_move', data: msg.data, userId: info.userId });
        }
        break;
      }
      case 'grid_update': {
        const info = wsUserMap.get(ws);
        if (info) {
          // Persist grid settings
          const rooms = readJSON('rooms.json');
          if (rooms[info.roomPin]) {
            rooms[info.roomPin].gridSettings = msg.data;
            writeJSON('rooms.json', rooms);
          }
          broadcastToRoom(info.roomPin, { type: 'grid_update', data: msg.data, userId: info.userId });
        }
        break;
      }
      case 'token_add': {
        const info = wsUserMap.get(ws);
        if (info) {
          const rooms = readJSON('rooms.json');
          if (rooms[info.roomPin]) {
            if (!rooms[info.roomPin].tokens) rooms[info.roomPin].tokens = {};
            if (msg.data && msg.data.id) {
              rooms[info.roomPin].tokens[msg.data.id] = msg.data;
            }
            writeJSON('rooms.json', rooms);
          }
          broadcastToRoom(info.roomPin, { type: 'token_add', data: msg.data, userId: info.userId });
        }
        break;
      }
      case 'token_remove': {
        const info = wsUserMap.get(ws);
        if (info) {
          const rooms = readJSON('rooms.json');
          if (rooms[info.roomPin]) {
            if (rooms[info.roomPin].tokens && msg.data && msg.data.id) {
              delete rooms[info.roomPin].tokens[msg.data.id];
            }
            writeJSON('rooms.json', rooms);
          }
          broadcastToRoom(info.roomPin, { type: 'token_remove', data: msg.data, userId: info.userId });
        }
        break;
      }
      case 'fog_reveal': {
        const info = wsUserMap.get(ws);
        if (info) {
          // Persist fog state
          const rooms = readJSON('rooms.json');
          if (rooms[info.roomPin]) {
            if (!rooms[info.roomPin].fogRevealed) rooms[info.roomPin].fogRevealed = [];
            rooms[info.roomPin].fogRevealed.push(msg.data);
            writeJSON('rooms.json', rooms);
          }
          broadcastToRoom(info.roomPin, { type: 'fog_reveal', data: msg.data, userId: info.userId });
        }
        break;
      }
      case 'achievement-unlocked': {
        const info = wsUserMap.get(ws);
        if (info) {
          broadcastToRoom(info.roomPin, { type: 'achievement-unlocked', data: msg.data });
        }
        break;
      }
      case 'loot-shared': {
        const info = wsUserMap.get(ws);
        if (info) {
          broadcastToRoom(info.roomPin, { type: 'loot-shared', data: msg.data });
        }
        break;
      }
      case 'chat_message': {
        const info = wsUserMap.get(ws);
        if (info && !info.isSpectator) {
          const chatData = {
            sender: info.userName,
            text: (msg.data && msg.data.text) || '',
            timestamp: Date.now(),
            isDM: info.isDM,
            isSystem: false
          };
          saveChatMessage(info.roomPin, chatData);
          broadcastToRoom(info.roomPin, { type: 'chat_message', data: chatData });
        }
        break;
      }
    }

    // Log events for session replay
    const wsInfo = wsUserMap.get(ws);
    if (wsInfo && wsInfo.roomPin) {
      const logTypes = ['dice-roll', 'initiative-update', 'chat-message', 'token_move'];
      if (logTypes.includes(msg.type)) {
        logSessionEvent(wsInfo.roomPin, {
          type: msg.type,
          data: msg.type === 'dice-roll'
            ? { userName: wsInfo.userName, notation: msg.notation, total: msg.total, results: msg.results, detail: msg.detail }
            : msg.type === 'chat-message'
            ? { userName: wsInfo.userName, message: msg.message }
            : msg.type === 'token_move'
            ? { userName: wsInfo.userName, tokenId: msg.data?.id, x: msg.data?.x, y: msg.data?.y }
            : { summary: 'Initiative updated' },
          timestamp: Date.now()
        });
      }
    }
  });

  ws.on('close', () => {
    const info = wsUserMap.get(ws);
    if (info && roomConnections[info.roomPin]) {
      roomConnections[info.roomPin].delete(ws);
      broadcastToRoom(info.roomPin, { type: 'user-left', userId: info.userId, userName: info.userName });
      // Send leave chat message
      if (!info.isSpectator) {
        const leaveMsg = { sender: 'System', text: `${info.userName} left the room`, timestamp: Date.now(), isSystem: true };
        saveChatMessage(info.roomPin, leaveMsg);
        broadcastToRoom(info.roomPin, { type: 'chat_message', data: leaveMsg });
      }
      broadcastSpectatorCount(info.roomPin);
      if (roomConnections[info.roomPin].size === 0) {
        delete roomConnections[info.roomPin];
      }
    }
  });
});

function broadcastToRoom(roomPin, data) {
  const conns = roomConnections[roomPin];
  if (!conns) return;
  const msg = JSON.stringify(data);
  for (const ws of conns) {
    if (ws.readyState === WebSocket.OPEN) ws.send(msg);
  }
}

function saveChatMessage(roomPin, chatData) {
  const rooms = readJSON('rooms.json');
  const room = rooms[roomPin];
  if (!room) return;
  if (!room.chatMessages) room.chatMessages = [];
  room.chatMessages.push(chatData);
  // Keep last 100
  if (room.chatMessages.length > 100) room.chatMessages = room.chatMessages.slice(-100);
  rooms[roomPin] = room;
  writeJSON('rooms.json', rooms);
}

function broadcastSpectatorCount(roomPin) {
  const conns = roomConnections[roomPin];
  if (!conns) return;
  let count = 0;
  for (const ws of conns) {
    const info = wsUserMap.get(ws);
    if (info && info.isSpectator) count++;
  }
  broadcastToRoom(roomPin, { type: 'spectator-count', count });
}

function saveRollHistory(roomPin, rollData) {
  const rooms = readJSON('rooms.json');
  const room = rooms[roomPin];
  if (!room) return;
  if (!room.rollHistory) room.rollHistory = [];
  room.rollHistory.push(rollData);
  if (room.rollHistory.length > 200) room.rollHistory = room.rollHistory.slice(-200);
  rooms[roomPin] = room;
  writeJSON('rooms.json', rooms);
}

function logSessionEvent(roomPin, event) {
  try {
    const rooms = readJSON('rooms.json');
    const room = rooms[roomPin];
    if (!room) return;
    if (!room.eventLog) room.eventLog = [];
    room.eventLog.push(event);
    if (room.eventLog.length > 1000) {
      room.eventLog = room.eventLog.slice(-1000);
    }
    rooms[roomPin] = room;
    writeJSON('rooms.json', rooms);
  } catch (e) {
    console.error('logSessionEvent error:', e.message);
  }
}

// Heartbeat
const interval = setInterval(() => {
  wss.clients.forEach((ws) => {
    if (!ws.isAlive) return ws.terminate();
    ws.isAlive = false;
    ws.ping();
  });
}, 30000);
wss.on('close', () => clearInterval(interval));

// --- REST API ---

// ============================================================
// ROOM MANAGEMENT
// ============================================================

// Create room — DM creates room, gets 6-digit DM PIN
app.post('/api/rooms', (req, res) => {
  const { dmName } = req.body;
  if (!dmName) return res.status(400).json({ error: 'DM name required' });

  const rooms = readJSON('rooms.json');
  const pin = generate6DigitPin(rooms);
  const dmId = uuidv4();

  rooms[pin] = {
    pin,
    dmId,
    dmName,
    createdAt: Date.now(),
    players: [],  // Players are now managed separately (not the DM)
    initiative: { combatants: [], currentTurn: 0, active: false },
    rollHistory: [],
    sessionNotes: '',
    summaries: []
  };
  writeJSON('rooms.json', rooms);
  // Create starter wiki page for the new room
  createStarterWikiPage(pin);
  res.json({ pin, dmId, dmName });
});

// ============================================================
// PLAYER MANAGEMENT (DM operations)
// ============================================================

// DM adds a player to the room
app.post('/api/rooms/:dmPin/players', (req, res) => {
  const { dmPin } = req.params;
  const { name } = req.body;
  if (!name) return res.status(400).json({ error: 'Player name required' });

  const rooms = readJSON('rooms.json');
  const room = rooms[dmPin];
  if (!room) return res.status(404).json({ error: 'Room not found' });

  // Check if name already exists in this room
  if (room.players.find(p => p.name.toLowerCase() === name.toLowerCase())) {
    return res.status(400).json({ error: 'Player name already exists in this room' });
  }

  const playerPin = generate4DigitPin(rooms);
  const playerId = uuidv4();
  const player = {
    id: playerId,
    name,
    pin: playerPin,
    characterId: null
  };

  room.players.push(player);
  rooms[dmPin] = room;
  writeJSON('rooms.json', rooms);

  res.json(player);
});

// DM gets list of all players with PINs
app.get('/api/rooms/:dmPin/players', (req, res) => {
  const { dmPin } = req.params;
  const rooms = readJSON('rooms.json');
  const room = rooms[dmPin];
  if (!room) return res.status(404).json({ error: 'Room not found' });
  res.json(room.players);
});

// DM removes a player
app.delete('/api/rooms/:dmPin/players/:playerId', (req, res) => {
  const { dmPin, playerId } = req.params;
  const rooms = readJSON('rooms.json');
  const room = rooms[dmPin];
  if (!room) return res.status(404).json({ error: 'Room not found' });

  const idx = room.players.findIndex(p => p.id === playerId);
  if (idx === -1) return res.status(404).json({ error: 'Player not found' });

  room.players.splice(idx, 1);
  rooms[dmPin] = room;
  writeJSON('rooms.json', rooms);

  res.json({ ok: true });
});

// DM regenerates a player's PIN
app.post('/api/rooms/:dmPin/players/:playerId/regen-pin', (req, res) => {
  const { dmPin, playerId } = req.params;
  const rooms = readJSON('rooms.json');
  const room = rooms[dmPin];
  if (!room) return res.status(404).json({ error: 'Room not found' });

  const player = room.players.find(p => p.id === playerId);
  if (!player) return res.status(404).json({ error: 'Player not found' });

  player.pin = generate4DigitPin(rooms);
  rooms[dmPin] = room;
  writeJSON('rooms.json', rooms);

  res.json(player);
});

// ============================================================
// AUTH — Unified PIN login
// ============================================================

// DM login with 6-digit PIN
app.post('/api/auth/dm', (req, res) => {
  const { pin } = req.body;
  if (!pin) return res.status(400).json({ error: 'PIN required' });

  const rooms = readJSON('rooms.json');
  const room = rooms[pin];
  if (!room) return res.status(404).json({ error: 'Invalid PIN' });

  res.json({
    roomPin: room.pin,
    dmId: room.dmId,
    dmName: room.dmName,
    players: room.players
  });
});

// Player login with 4-digit PIN — search all rooms
app.post('/api/auth/player', (req, res) => {
  const { pin } = req.body;
  if (!pin) return res.status(400).json({ error: 'PIN required' });

  const rooms = readJSON('rooms.json');

  for (const roomPin of Object.keys(rooms)) {
    const room = rooms[roomPin];
    if (!room.players) continue;
    const player = room.players.find(p => p.pin === pin);
    if (player) {
      return res.json({
        roomPin: room.pin,
        playerId: player.id,
        playerName: player.name,
        characterId: player.characterId
      });
    }
  }

  res.status(404).json({ error: 'Invalid PIN' });
});

