// Save session to Obsidian
app.post('/api/sessions/save-to-obsidian', (req, res) => {
  try {
    const { roomPin, sessionName } = req.body;
    if (!roomPin) return res.status(400).json({ error: 'roomPin required' });

    const rooms = readJSON('rooms.json');
    const room = rooms[roomPin];
    if (!room) return res.status(404).json({ error: 'Room not found' });

    const chars = readJSON('characters.json');
    const roomChars = Object.values(chars).filter(c => c.roomPin === roomPin);

    const now = new Date();
    const dateStr = now.toISOString().slice(0, 10);
    const dateDisplay = now.toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });

    const dmName = room.dmName || 'Unknown DM';
    const playerNames = roomChars.map(c => c.playerName || c.name).filter(Boolean);
    const displayName = sessionName || `Session`;

    // Build markdown
    let md = `---\ndate: ${dateStr}\ntype: dnd-session\nroom: ${roomPin}\ndm: ${dmName}\nplayers: [${playerNames.join(', ')}]\n---\n\n`;
    md += `# D&D Session — ${dateDisplay}\n\n`;

    // Party table
    if (roomChars.length > 0) {
      md += `## Party\n`;
      md += `| Player | Character | Species | Class | Level | HP |\n`;
      md += `|--------|-----------|---------|-------|-------|----|` + `\n`;
      roomChars.forEach(c => {
        const maxHP = calcMaxHP(c);
        const currentHP = c.currentHP !== undefined ? c.currentHP : maxHP;
        md += `| ${c.playerName || '?'} | ${c.name || '?'} | ${c.species || '?'} | ${c.className || '?'} | ${c.level || 1} | ${currentHP}/${maxHP} |\n`;
      });
      md += `\n`;
    }

    // Session Notes
    md += `## Session Notes\n`;
    if (room.sessionNotes && room.sessionNotes.trim()) {
      md += `${room.sessionNotes.trim()}\n\n`;
    } else {
      md += `*No notes recorded for this session.*\n\n`;
    }

    // AI Summaries
    md += `## AI Summary\n`;
    if (room.summaries && room.summaries.length > 0) {
      room.summaries.forEach(s => {
        md += `### ${new Date(s.timestamp).toLocaleString()}\n`;
        md += `${s.content}\n\n`;
      });
    } else {
      md += `*No AI summary generated.*\n\n`;
    }

    // Combat Log from initiative
    md += `## Combat Log\n`;
    if (room.initiative && room.initiative.combatants && room.initiative.combatants.length > 0) {
      room.initiative.combatants.forEach(c => {
        const condStr = (c.conditions && c.conditions.length) ? ` [${c.conditions.join(', ')}]` : '';
        md += `- ${c.name}: HP ${c.currentHP}/${c.maxHP}${condStr}\n`;
      });
      md += `\n`;
    } else {
      md += `*No combat tracked.*\n\n`;
    }

    // Dice Roll Highlights
    const rolls = room.rollHistory || [];
    md += `## Dice Roll Highlights\n`;
    if (rolls.length > 0) {
      // Find nat 20s and nat 1s
      const highlights = rolls.filter(r => {
        if (!r.results) return false;
        return r.results.includes(20) || r.results.includes(1);
      });
      if (highlights.length > 0) {
        highlights.forEach(r => {
          if (r.results.includes(20)) {
            md += `- 🎯 ${r.userName || 'Unknown'} rolled **Nat 20**! (${r.notation || '?'} → ${r.total})\n`;
          }
          if (r.results.includes(1)) {
            md += `- 💀 ${r.userName || 'Unknown'} rolled **Nat 1**! (${r.notation || '?'} → ${r.total})\n`;
          }
        });
      } else {
        md += `*No critical hits or fumbles this session.*\n`;
      }
      md += `\n`;
    } else {
      md += `*No rolls recorded.*\n\n`;
    }

    // Session Stats
    md += `## Session Stats\n`;
    md += `- Rolls made: ${rolls.length}\n`;
    const uniqueRollers = new Set(rolls.map(r => r.userName).filter(Boolean));
    md += `- Players who rolled: ${uniqueRollers.size > 0 ? [...uniqueRollers].join(', ') : 'None'}\n`;
    if (room.initiative && room.initiative.combatants && room.initiative.combatants.length > 0) {
      const monsters = room.initiative.combatants.filter(c => c.type === 'monster');
      md += `- Combatants tracked: ${room.initiative.combatants.length} (${monsters.length} monsters)\n`;
    }
    md += `\n`;

    // Save file
    const safeSessionName = displayName.replace(/[/\\?%*:|"<>]/g, '-');
    const filename = `${dateStr} - ${safeSessionName}.md`;
    const filepath = path.join(OBSIDIAN_SESSIONS_DIR, filename);
    fs.writeFileSync(filepath, md, 'utf8');

    res.json({ ok: true, filename, filepath });
  } catch (e) {
    console.error('Save to Obsidian failed:', e);
    res.status(500).json({ error: 'Failed to save: ' + e.message });
  }
});

