// Session history — list files from Obsidian vault
app.get('/api/sessions/history', (req, res) => {
  try {
    if (!fs.existsSync(OBSIDIAN_SESSIONS_DIR)) {
      return res.json([]);
    }
    const files = fs.readdirSync(OBSIDIAN_SESSIONS_DIR)
      .filter(f => f.endsWith('.md'))
      .sort()
      .reverse();

    const sessions = files.map(f => {
      try {
        const content = fs.readFileSync(path.join(OBSIDIAN_SESSIONS_DIR, f), 'utf8');
        // Parse frontmatter
        const fmMatch = content.match(/^---\n([\s\S]*?)\n---/);
        let meta = {};
        if (fmMatch) {
          const lines = fmMatch[1].split('\n');
          lines.forEach(line => {
            const [key, ...val] = line.split(':');
            if (key && val.length) {
              const value = val.join(':').trim();
              meta[key.trim()] = value;
            }
          });
        }

        // Extract brief summary (first 200 chars after Session Notes heading)
        const notesMatch = content.match(/## Session Notes\n([\s\S]*?)(?=\n## |$)/);
        const briefNotes = notesMatch ? notesMatch[1].trim().slice(0, 200) : '';

        // Parse players from frontmatter
        let players = [];
        if (meta.players) {
          const pMatch = meta.players.match(/\[(.*?)\]/);
          if (pMatch) players = pMatch[1].split(',').map(p => p.trim()).filter(Boolean);
        }

        return {
          filename: f,
          date: meta.date || f.slice(0, 10),
          dm: meta.dm || 'Unknown',
          room: meta.room || '?',
          players,
          briefNotes
        };
      } catch {
        return { filename: f, date: f.slice(0, 10), dm: 'Unknown', room: '?', players: [], briefNotes: '' };
      }
    });

    res.json(sessions);
  } catch (e) {
    console.error('Session history failed:', e);
    res.status(500).json({ error: e.message });
  }
});

