app.post('/api/characters/generate', async (req, res) => {
  const { prompt, level, className, species } = req.body;
  if (!prompt) return res.status(400).json({ error: 'Prompt/description required' });

  const lvl = level || 1;
  const classHint = className && className !== 'Any' ? `Class preference: ${className}.` : '';
  const speciesHint = species && species !== 'Any' ? `Species preference: ${species}.` : '';

  // Build SRD-aware prompt with real spell/equipment names
  const chargenClass = className && className !== 'Any' ? className : null;
  const srdSpells = getSRDData('spells', '2024');
  const srdEquipment = getSRDData('equipment', '2024');
  const srdFeats = getSRDData('feats', '2024');

  // Get spells for this class (or all if Any)
  let relevantSpells = srdSpells;
  if (chargenClass) {
    relevantSpells = srdSpells.filter(s => s.classes && s.classes.some(c => (c.name || c).toLowerCase() === chargenClass.toLowerCase()));
  }
  const spellNames = relevantSpells.filter(s => s.level <= Math.min(lvl, 9)).slice(0, 40).map(s => s.name);
  const weaponNames = srdEquipment.filter(e => (e.equipment_category?.name || '').toLowerCase().includes('weapon')).map(e => e.name);
  const armorNames = srdEquipment.filter(e => (e.equipment_category?.name || '').toLowerCase().includes('armor')).map(e => e.name);
  const featNames = srdFeats.map(f => f.name);

  const srdContext = `
IMPORTANT: Use ONLY real D&D 5e SRD spell names, equipment names, and feat names from these lists:
Available spells (pick appropriate ones for level ${lvl}): ${spellNames.join(', ')}.
Available weapons: ${weaponNames.join(', ')}.
Available armor: ${armorNames.join(', ')}.
Available feats: ${featNames.join(', ')}.
Do NOT invent spell names or equipment that don't exist in D&D 5e SRD.`;

  const aiPrompt = `Generate a D&D 2024 player character. ${prompt}. Level: ${lvl}. ${classHint} ${speciesHint}${srdContext} Return ONLY valid JSON (no markdown, no explanation, no code fences) with these exact fields: {"name": string, "species": string (one of: Human, Elf, Dwarf, Halfling, Orc, Tiefling, Dragonborn, Gnome, Goliath, Aasimar), "className": string (one of: Barbarian, Bard, Cleric, Druid, Fighter, Monk, Paladin, Ranger, Rogue, Sorcerer, Warlock, Wizard), "background": string (one of: Acolyte, Artisan, Charlatan, Criminal, Entertainer, Farmer, Guard, Guide, Hermit, Merchant, Noble, Sage, Sailor, Scribe, Soldier, Wayfarer), "level": number, "str": number, "dex": number, "con": number, "int": number, "wis": number, "cha": number, "hp": number, "maxHp": number, "ac": number, "speed": number, "alignment": string, "personalityTraits": string, "ideals": string, "bonds": string, "flaws": string, "backstory": string, "appearance": string, "equipment": string, "proficientSkills": array of skill name strings (from: Acrobatics, Animal Handling, Arcana, Athletics, Deception, History, Insight, Intimidation, Investigation, Medicine, Nature, Perception, Performance, Persuasion, Religion, Sleight of Hand, Stealth, Survival), "features": array of {"name": string, "desc": string}}. Make ability scores realistic for the class. Make the character interesting and flavorful.`;

  try {
    const response = await fetch('http://127.0.0.1:3001/voice/chat', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ agentId: 'sarael', message: aiPrompt })
    });
    const data = await response.json();
    const rawText = data.response || data.message || JSON.stringify(data);

    let charData;
    try {
      charData = JSON.parse(rawText);
    } catch {
      // Try to extract JSON from markdown fences or find JSON object
      const fenceMatch = rawText.match(/```(?:json)?\s*([\s\S]*?)```/);
      if (fenceMatch) {
        try { charData = JSON.parse(fenceMatch[1].trim()); } catch {}
      }
      if (!charData) {
        const jsonMatch = rawText.match(/\{[\s\S]*\}/);
        if (jsonMatch) {
          try { charData = JSON.parse(jsonMatch[0]); } catch {}
        }
      }
      if (!charData) {
        return res.status(500).json({ error: 'AI returned invalid JSON', raw: rawText.slice(0, 500) });
      }
    }

    // Normalize and validate the response
    const result = {
      name: charData.name || 'Unknown Hero',
      species: charData.species || charData.race || 'Human',
      className: charData.className || charData.class || 'Fighter',
      background: charData.background || 'Soldier',
      level: charData.level || lvl,
      str: charData.str || 10,
      dex: charData.dex || 10,
