app.put('/api/rooms/:pin/wiki/:id', (req, res) => {
  const wiki = readJSON('wiki.json');
  const pages = wiki[req.params.pin] || [];
  const idx = pages.findIndex(p => p.id === req.params.id);
  if (idx === -1) return res.status(404).json({ error: 'Wiki page not found' });

  pages[idx] = {
    ...pages[idx],
    title: req.body.title !== undefined ? req.body.title : pages[idx].title,
    category: req.body.category !== undefined ? req.body.category : pages[idx].category,
    content: req.body.content !== undefined ? req.body.content : pages[idx].content,
    tags: req.body.tags !== undefined ? req.body.tags : pages[idx].tags,
    linkedPages: req.body.linkedPages !== undefined ? req.body.linkedPages : pages[idx].linkedPages,
    published: req.body.published !== undefined ? req.body.published : pages[idx].published,
    updatedAt: Date.now()
  };

  wiki[req.params.pin] = pages;
  writeJSON('wiki.json', wiki);
  res.json(pages[idx]);
});

