app.post('/api/ai-dm/chat', async (req, res) => {
  const { characterData, conversationHistory, playerAction, genre } = req.body;
  if (!characterData) return res.status(400).json({ error: 'Character data required' });

  // Build context from conversation history
  let historyText = '';
  if (conversationHistory && conversationHistory.length > 0) {
    // If history is too long, only keep recent + a summary note
    const recentHistory = conversationHistory.slice(-30);
    historyText = recentHistory.map(m => {
      if (m.role === 'dm') return `DM: ${m.text}`;
      if (m.role === 'player') return `Player: ${m.text}`;
      if (m.role === 'system') return `[System: ${m.text}]`;
      return m.text;
    }).join('\n\n');
  }

  const genreHint = genre ? `Adventure genre: ${genre}.` : '';

  const aiPrompt = `You are a D&D 2024 Dungeon Master running a solo adventure. Be dramatic, engaging, and immersive.

CHARACTER:
Name: ${characterData.name || 'Unknown'}
Species: ${characterData.species || '?'}, Class: ${characterData.className || '?'}, Level: ${characterData.level || 1}
HP: ${characterData.currentHP || '?'}/${characterData.maxHP || '?'}, AC: ${characterData.ac || '?'}
STR: ${characterData.str || 10}, DEX: ${characterData.dex || 10}, CON: ${characterData.con || 10}, INT: ${characterData.int || 10}, WIS: ${characterData.wis || 10}, CHA: ${characterData.cha || 10}
${characterData.notes ? `Notes/Equipment: ${characterData.notes}` : ''}

${genreHint}

STORY SO FAR:
${historyText || '(New adventure - set the opening scene)'}

${playerAction ? `PLAYER ACTION: ${playerAction}` : 'Begin the adventure with a vivid opening scene.'}

INSTRUCTIONS:
- Respond with vivid narrative (2-4 paragraphs). Include NPC dialogue in quotes.
- If a skill check or combat is needed, specify the roll required.
- Track the story. Be dramatic and engaging.
- IMPORTANT: Return ONLY valid JSON (no markdown, no code fences) with these fields:
{
  "narrative": "Your narrative text here (2-4 paragraphs, use \\n for line breaks)",
  "rollRequired": null or {"type": "d20", "skill": "Stealth", "modifier": "Dexterity", "dc": 15, "description": "Roll a d20 + Dexterity modifier for Stealth"},
  "combatState": null or {"inCombat": true, "enemies": [{"name": "Goblin", "hp": 7, "ac": 15}], "description": "Combat begins!"},
  "location": "Current location name",
  "suggestions": ["suggestion 1", "suggestion 2", "suggestion 3"]
}`;

  try {
    const response = await fetch('http://127.0.0.1:3001/voice/chat', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ agentId: 'sarael', message: aiPrompt })
    });
    const data = await response.json();
    const rawText = data.response || data.message || JSON.stringify(data);

    let result;
    try {
      result = JSON.parse(rawText);
    } catch {
      // Try to extract JSON from response
      const fenceMatch = rawText.match(/```(?:json)?\s*([\s\S]*?)```/);
      if (fenceMatch) {
        try { result = JSON.parse(fenceMatch[1].trim()); } catch {}
      }
      if (!result) {
        const jsonMatch = rawText.match(/\{[\s\S]*\}/);
        if (jsonMatch) {
          try { result = JSON.parse(jsonMatch[0]); } catch {}
        }
      }
      if (!result) {
        // Fallback: wrap raw text as narrative
        result = {
          narrative: rawText,
          rollRequired: null,
          combatState: null,
          location: null,
          suggestions: []
        };
      }
    }

    // Normalize result
    res.json({
      narrative: result.narrative || rawText,
      rollRequired: result.rollRequired || null,
      combatState: result.combatState || null,
      location: result.location || null,
      suggestions: Array.isArray(result.suggestions) ? result.suggestions : []
    });
  } catch (err) {
    res.status(500).json({ error: 'AI service unavailable: ' + err.message });
  }
});

