      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ agentId: 'sarael', message: aiPrompt })
    });
    const data = await response.json();
    const rawText = data.response || data.message || '{}';

    let questData;
