  const transFile = path.join(SRD_DIR, 'translations-id.json');
  if (fs.existsSync(transFile)) {
    SRD_TRANSLATIONS['id'] = JSON.parse(fs.readFileSync(transFile, 'utf8'));
    console.log('SRD translations loaded: id (' + Object.keys(SRD_TRANSLATIONS['id']).length + ' sections)');
  }
} catch (e) {
  console.error('Failed to load SRD translations:', e.message);
}

app.get('/api/srd/translations/:lang', (req, res) => {
  const lang = req.params.lang.toLowerCase();
  if (SRD_TRANSLATIONS[lang]) res.json(SRD_TRANSLATIONS[lang]);
  else res.status(404).json({ error: `Translation not found for language: ${lang}` });
});

// Source books list
app.get('/api/srd/sources', (req, res) => {
  res.json(SOURCE_BOOKS);
});

// ---- Spells ----
app.get('/api/srd/spells', (req, res) => {
  const { search, level, school, className, source, page, limit } = req.query;
  let data = COMPENDIUM.spells;
  if (search) data = searchCompendium(data, search);
  if (level !== undefined && level !== '') {
    const lvl = parseInt(level);
    data = data.filter(s => s.level === lvl);
  }
  if (school) {
    const sch = school.toLowerCase();
    data = data.filter(s => (s.school || '').toLowerCase().includes(sch));
  }
  if (className) {
    const cls = className.toLowerCase();
    data = data.filter(s => Array.isArray(s.classes) && s.classes.some(c => (c || '').toLowerCase() === cls));
  }
  if (source) data = data.filter(s => s.source === source);
  if (page || limit) return res.json(paginate(data, page, limit));
  res.json(data);
});

// ---- Monsters (empty for PHB-only, kept for compat) ----
app.get('/api/srd/monsters', (req, res) => {
  const { search, cr, crMin, crMax, type, source, page, limit } = req.query;
  let data = COMPENDIUM.monsters || [];
  if (search) data = searchCompendium(data, search);
  if (cr !== undefined && cr !== '') data = data.filter(m => m.cr === cr);
  if (type) { const t = type.toLowerCase(); data = data.filter(m => (m.type || '').toLowerCase().includes(t)); }
  if (source) data = data.filter(m => m.source === source);
  if (page || limit) return res.json(paginate(data, page, limit));
  res.json(paginate(data, 1, 50));
});

// ---- Classes ----
app.get('/api/srd/classes', (req, res) => {
  const { search } = req.query;
  let data = COMPENDIUM.classes;
  if (search) data = searchCompendium(data, search);
  res.json(data);
});

// ---- Items (all equipment) ----
app.get('/api/srd/items', (req, res) => {
  const { search, type, rarity, source, magic, page, limit } = req.query;
  let data = COMPENDIUM.items;
  if (search) data = searchCompendium(data, search);
  if (type) {
    const t = type.toLowerCase();
    data = data.filter(i => (i.type || '').toLowerCase().includes(t));
  }
  if (rarity) {
    const r = rarity.toLowerCase();
    data = data.filter(i => (i.rarity || '').toLowerCase() === r);
  }
  if (magic === 'true') data = data.filter(i => i.isMagicItem);
  else if (magic === 'false') data = data.filter(i => !i.isMagicItem);
  if (source) data = data.filter(i => i.source === source);
  if (page || limit) return res.json(paginate(data, page, limit));
  res.json(data);
