  if (search) data = searchSRD(data, search);
  res.json(data);
});

// Aggregate endpoint — all categories with counts
app.get('/api/srd/summary', (req, res) => {
  const summary = {};
  for (const [cat, items] of Object.entries(COMPENDIUM)) {
    summary[cat] = items.length;
  }
  res.json({ categories: summary, sources: SOURCE_BOOKS });
});

// SRD data for AI character generation — curated lists (legacy)
app.get('/api/srd/chargen-data', (req, res) => {
  const spells = getSRDData('spells', '2024');
  const equipment = getSRDData('equipment', '2024');
  const magicItems = getSRDData('magic-items', '2024');
  const feats = getSRDData('feats', '2024');
  const backgrounds = getSRDData('backgrounds', '2024');

  const spellsByClass = {};
  spells.forEach(s => {
    if (s.classes) {
      s.classes.forEach(c => {
        const cname = c.name || c;
        if (!spellsByClass[cname]) spellsByClass[cname] = [];
        spellsByClass[cname].push({ name: s.name, level: s.level });
      });
    }
  });

  const weapons = equipment.filter(e => {
    const cat = (e.equipment_category?.name || e.equipment_category || '').toLowerCase();
    const cats = Array.isArray(e.equipment_categories) ? e.equipment_categories.map(c => (c.name || '').toLowerCase()) : [];
    return cat.includes('weapon') || cats.some(c => c.includes('weapon'));
  }).map(e => e.name);

  const armor = equipment.filter(e => {
    const cat = (e.equipment_category?.name || e.equipment_category || '').toLowerCase();
    const cats = Array.isArray(e.equipment_categories) ? e.equipment_categories.map(c => (c.name || '').toLowerCase()) : [];
    return cat.includes('armor') || cats.some(c => c.includes('armor'));
  }).map(e => e.name);

  const gear = equipment.filter(e => {
    const cat = (e.equipment_category?.name || e.equipment_category || '').toLowerCase();
    const cats = Array.isArray(e.equipment_categories) ? e.equipment_categories.map(c => (c.name || '').toLowerCase()) : [];
    return cat.includes('adventuring') || cat.includes('gear') || cat.includes('standard') || cats.some(c => c.includes('adventuring'));
  }).map(e => e.name);

  res.json({
    spellsByClass,
    weapons,
    armor,
    gear,
    magicItemNames: magicItems.map(i => i.name),
    featNames: feats.map(f => f.name),
    backgroundNames: backgrounds.map(b => b.name),
  });
});

server.listen(PORT, () => {
  console.log(`D&D 2024 App running on port ${PORT}`);
});

