arguments.newText:
// ============================================================
// AI CHAT ASSISTANT
// ============================================================

// Helper: find room by DM pin or player pin
function findRoomByAnyPin(pin) {
  const rooms = readJSON('rooms.json');
  // Check DM pins
  if (rooms[pin]) return rooms[pin];
  // Check player pins
  for (const room of Object.values(rooms)) {
    if (room.players?.some(p => p.pin === pin)) return room;
  }
  return null;
}

// Gather session context for AI
function gatherSessionContext(room) {
  const ctx = [];

  // Party info
  if (room.players?.length) {
    ctx.push('## Current Party');
    for (const p of room.players) {
      // Try to find character data
      const chars = readJSON('characters.json');
      let char = {};
      if (p.characterId && chars[p.characterId]) {
        char = chars[p.characterId];
      }
      const race = char.species || char.race || '?';
      const cls = char.className || char.class || '?';
      const level = char.level || 1;
      const hp = char.currentHP !== undefined ? char.currentHP : (char.hp || '?');
      const maxHp = char.maxHp || char.maxHP || '?';
      const ac = char.ac || '?';
      ctx.push(`- **${p.name}** (${race} ${cls} Lv${level}) HP: ${hp}/${maxHp} AC: ${ac}`);
    }
  }

  // Initiative order (if combat active)
  const initiative = room.initiative;
  if (initiative && initiative.combatants && initiative.combatants.length > 0) {
    ctx.push('\n## Initiative Order');
    initiative.combatants.forEach((entry, i) => {
      const current = (initiative.currentTurn === i) ? ' ← CURRENT TURN' : '';
      ctx.push(`${i + 1}. ${entry.name} (${entry.initiative || entry.roll || '?'})${current}`);
    });
  }

  // Recent dice rolls (last 10)
  if (room.rollHistory?.length) {
    ctx.push('\n## Recent Dice Rolls');
    room.rollHistory.slice(-10).forEach(r => {
      ctx.push(`- ${r.userName || 'Unknown'}: ${r.notation || '?'} = **${r.total}** ${r.detail || ''}`);
    });
  }

  // Session notes
  if (room.sessionNotes) {
    ctx.push('\n## Session Notes');
    ctx.push(room.sessionNotes);
  }

  return ctx.join('\n');
}

const AI_CHAT_HISTORY = {}; // roomPin → [{role, content}]
const AI_RATE_LIMIT = {};   // roomPin → timestamp

// AI Chat endpoint
app.post('/api/rooms/:pin/ai-chat', async (req, res) => {
  const { message } = req.body;
  if (!message) return res.status(400).json({ ok: false, error: 'Message required' });

  const room = findRoomByAnyPin(req.params.pin);
  if (!room) return res.status(404).json({ ok: false, error: 'Room not found' });

  const roomPin = room.pin || req.params.pin;

  // Rate limiting: 1 request per 3 seconds per room
  const now = Date.now();
  if (AI_RATE_LIMIT[roomPin] && now - AI_RATE_LIMIT[roomPin] < 3000) {
    return res.status(429).json({ ok: false, error: 'Please wait a moment before asking again' });
  }
  AI_RATE_LIMIT[roomPin] = now;

  // Initialize history
  if (!AI_CHAT_HISTORY[roomPin]) AI_CHAT_HISTORY[roomPin] = [];
  const history = AI_CHAT_HISTORY[roomPin];

  // Gather context
  const context = gatherSessionContext(room);

  // Add user message
  history.push({ role: 'user', content: message });

  // Keep last 20 messages
  if (history.length > 20) history.splice(0, history.length - 20);

  // Build system prompt
  const systemPrompt = `You are a D&D 5e (2024 rules) game assistant. You help both DMs and Players.

Your knowledge:
- All D&D 2024 Player's Handbook rules
- Monsters, spells, items, conditions
- Creative encounter design
- NPC roleplay and voices
- Rules interpretation

Current session context:
${context}

Guidelines:
- Be concise but helpful
- Use D&D terminology correctly
- When suggesting encounters, consider party level and composition
- When asked about rules, cite the relevant rule
- For roleplay, be creative and engaging
- If asked to make a decision for a player, suggest options instead
- Respond in the same language the user writes in
- Use emoji for flavor (⚔️ for combat, 🎲 for dice, 🧙 for magic, etc.)`;

  // Build the full prompt with conversation history
  let fullPrompt = systemPrompt + '\n\n';
  // Include recent history for context
  const recentHistory = history.slice(0, -1); // exclude the latest user message (it'll be the main prompt)
  if (recentHistory.length > 0) {
    fullPrompt += 'Conversation so far:\n';
    recentHistory.forEach(m => {
      fullPrompt += `${m.role === 'user' ? 'User' : 'Assistant'}: ${m.content}\n\n`;
    });
  }
  fullPrompt += `User: ${message}\n\nRespond helpfully:`;

  // Call AI via same pattern as /api/rooms/:pin/summary (Council Room proxy)
  try {
    const response = await fetch('http://127.0.0.1:3001/voice/chat', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ agentId: 'sarael', message: fullPrompt })
    });
    const data = await response.json();
    const aiResponse = data.response || data.message || 'The oracle is silent...';

    history.push({ role: 'assistant', content: aiResponse });
    res.json({ ok: true, response: aiResponse, historyLength: history.length });
  } catch (e) {
    // Remove the user message on failure so it can be retried
    history.pop();
    res.status(500).json({ ok: false, error: 'AI service unavailable: ' + e.message });
  }
});

// Clear AI chat history
app.delete('/api/rooms/:pin/ai-chat', (req, res) => {
  const room = findRoomByAnyPin(req.params.pin);
  if (!room) return res.status(404).json({ ok: false, error: 'Room not found' });
  const roomPin = room.pin || req.params.pin;
  AI_CHAT_HISTORY[roomPin] = [];
  res.json({ ok: true });
});

// Health check
app.get('/api/health', (req, res) => {
  res.json({ status: 'ok', uptime: process.uptime() });
});

